    result = {"approved": False}

    def step_check():
        result["approved"] = check_balance(name, amount)
        return ("check", result["approved"])

    def step_act():
        # Re-validate at act time to prevent stale approvals from overdrafting.
        current_ok = check_balance(name, amount)
        if current_ok:
            do_withdraw(name, amount)
        result["approved"] = current_ok
        return ("act", current_ok)

    return step_check, step_act


